 31→#[template(path = "next_actions.html")]
 32→struct NextActionsTemplate {
 33→    current_page: &'static str,
 34→    inbox_count: i64,
 35→    actions: Vec<NextActionView>,
 36→    contexts: Vec<ContextOption>,
 37→    selected_context: Option<String>,
 38→    error_message: Option<String>,
