 53→fn build_action_view(action: &NextAction, contexts: &[Context]) -> NextActionView {
 54→    let context_name = contexts
 55→        .iter()
 56→        .find(|c| c.id() == action.context_id())
 57→        .map(|c| c.name().as_str().to_string())
 58→        .unwrap_or_else(|| "Unknown".to_string());
 59→
 60→    NextActionView {
 61→        id: action.id().as_uuid().to_string(),
 62→        title: action.title().as_str().to_string(),
 63→        context_name,
 64→    }
 65→}
 66→
 67→#[derive(serde::Deserialize)]
 68→pub struct ContextFilter {
 69→    pub context: Option<Uuid>,
 70→}
 71→
 72→pub async fn get_next_actions(
 73→    AuthenticatedUser(user_id): AuthenticatedUser,
 74→    State(pool): State<PgPool>,
 75→    Query(filter): Query<ContextFilter>,
 76→) -> Result<impl IntoResponse, NextActionError> {
 77→    let inbox_count = inbox_service::get_inbox_count(&pool, &user_id)
 78→        .await
 79→        .map_err(NextActionError::Unexpected)?;
 80→
 81→    let contexts = context_service::list_contexts(&pool, &user_id)
 82→        .await
 83→        .map_err(NextActionError::Unexpected)?;
 84→
 85→    let actions = if let Some(ctx_uuid) = filter.context {
 86→        let ctx_id = ContextId::from_uuid(ctx_uuid);
 87→        next_action_service::list_active_next_actions_by_context(&pool, &user_id, &ctx_id)
 88→            .await
 89→            .map_err(NextActionError::Unexpected)?
 90→    } else {
 91→        next_action_service::list_active_next_actions(&pool, &user_id)
 92→            .await
 93→            .map_err(NextActionError::Unexpected)?
 94→    };
 95→
 96→    let action_views: Vec<NextActionView> = actions
 97→        .iter()
 98→        .map(|a| build_action_view(a, &contexts))
 99→        .collect();
100→
101→    let context_options: Vec<ContextOption> = contexts
102→        .iter()
103→        .map(|c| ContextOption {
104→            id: c.id().as_uuid().to_string(),
105→            name: c.name().as_str().to_string(),
106→        })
107→        .collect();
108→
109→    let selected_context = filter.context.map(|c| c.to_string());
110→
111→    let template = NextActionsTemplate {
112→        current_page: "next_actions",
113→        inbox_count,
114→        actions: action_views,
115→        contexts: context_options,
116→        selected_context,
117→        error_message: None,
118→    };
119→    Ok(Html(template.render()?))
120→}
121→
122→#[derive(serde::Deserialize)]
123→pub struct AddNextActionForm {
124→    pub title: String,
125→    pub context_id: Uuid,
126→}
127→
128→pub async fn post_next_action(
129→    AuthenticatedUser(user_id): AuthenticatedUser,
130→    State(pool): State<PgPool>,
131→    headers: HeaderMap,
132→    Form(form): Form<AddNextActionForm>,
133→) -> Result<Response, NextActionError> {
134→    let htmx = is_htmx_request(&headers);
135→
136→    if form.title.trim().is_empty() {
137→        if htmx {
138→            return Ok(StatusCode::NO_CONTENT.into_response());
139→        }
140→        return Ok(Redirect::to("/next-actions").into_response());
141→    }
142→
143→    let context_id = ContextId::from_uuid(form.context_id);
144→
145→    let contexts = context_service::list_contexts(&pool, &user_id)
146→        .await
147→        .map_err(NextActionError::Unexpected)?;
148→
149→    match next_action_service::add_next_action(&pool, user_id.clone(), context_id, form.title).await
150→    {
151→        Ok(action) => {
152→            if htmx {
153→                let template = NextActionItemTemplate {
154→                    action: build_action_view(&action, &contexts),
155→                };
156→                let body = template.render().map_err(NextActionError::Render)?;
157→                Ok(htmx_response_with_announce(Html(body), "Next action added"))
158→            } else {
159→                Ok(Redirect::to("/next-actions").into_response())
160→            }
161→        }
162→        Err(AddNextActionError::InvalidTitle(title_err)) => {
163→            let user_facing = match title_err {
164→                TodoTitleError::Empty => {
165→                    if htmx {
166→                        return Ok(StatusCode::NO_CONTENT.into_response());
167→                    }
168→                    return Ok(Redirect::to("/next-actions").into_response());
169→                }
170→                TodoTitleError::TooLong { max, .. } => {
171→                    format!("That title is too long (max {max} characters)")
172→                }
173→            };
174→
175→            render_next_actions_with_error(&pool, &user_id, &user_facing).await
176→        }
177→        Err(AddNextActionError::Unexpected(err)) => Err(NextActionError::Unexpected(err)),
178→    }
179→}
180→
181→async fn render_next_actions_with_error(
182→    pool: &PgPool,
183→    user_id: &crate::domain::UserId,
184→    error_message: &str,
185→) -> Result<Response, NextActionError> {
186→    let inbox_count = inbox_service::get_inbox_count(pool, user_id)
187→        .await
188→        .map_err(NextActionError::Unexpected)?;
