{% extends "base.html" %}

{% block title %}Next Actions -- Todo List{% endblock %}

{% block nav %}
{% include "gtd_nav.html" %}
{% endblock %}

{% block content %}
<div class="next-actions">
    <h1>Next Actions</h1>

    {% if let Some(error) = error_message %}
    <div class="next-actions__error" role="alert">{{ error }}</div>
    {% endif %}

    <nav class="next-actions__filters" aria-label="Filter by context">
        <ul class="next-actions__filter-list" role="list">
            <li>
                <a href="/next-actions"{% if selected_context.is_none() %} aria-current="true" class="next-actions__filter-link next-actions__filter-link--active"{% else %} class="next-actions__filter-link"{% endif %}>All</a>
            </li>
            {% for ctx in contexts %}
            <li>
                <a href="/next-actions?context={{ ctx.id }}"{% if selected_context.as_deref() == Some(ctx.id.as_str()) %} aria-current="true" class="next-actions__filter-link next-actions__filter-link--active"{% else %} class="next-actions__filter-link"{% endif %}>{{ ctx.name }}</a>
            </li>
            {% endfor %}
        </ul>
    </nav>

    {% if !contexts.is_empty() %}
    <form
        method="post"
        action="/next-actions"
        class="next-actions__add"
        hx-post="/next-actions"
        hx-target="#next-actions-list"
        hx-swap="beforeend"
        hx-on::after-request="if(event.detail.successful) { this.querySelector('#next-action-title').value = ''; this.querySelector('#next-action-title').focus(); }"
    >
        <label for="next-action-title">Add next action</label>
        <div class="next-actions__add-row">
            <input
                type="text"
                id="next-action-title"
                name="title"
                placeholder="What's the next action?"
                maxlength="300"
                autocomplete="off"
                class="next-actions__add-input"
            >
            <select id="next-action-context" name="context_id" class="next-actions__add-context" aria-label="Context">
                {% for ctx in contexts %}
                <option value="{{ ctx.id }}">{{ ctx.name }}</option>
                {% endfor %}
            </select>
            <button type="submit" class="next-actions__add-submit">Add</button>
        </div>
    </form>
    {% endif %}

    {% if actions.is_empty() %}
    <div class="next-actions__empty-state" id="next-actions-empty-state">
        <p>No next actions yet. Process your <a href="/inbox">inbox</a> to find things to do.</p>
    </div>
    {% endif %}
    <ul class="next-actions__list" role="list" id="next-actions-list"{% if actions.is_empty() %} hidden{% endif %}>
        {% for action in actions %}
        {% include "next_action_item.html" %}
        {% endfor %}
    </ul>
</div>
{% endblock %}

{% block scripts %}
<script>
document.getElementById('next-actions-list').addEventListener('htmx:afterSwap', function() {
    var list = document.getElementById('next-actions-list');
    var emptyState = document.getElementById('next-actions-empty-state');
    if (list && list.children.length > 0) {
        list.hidden = false;
        if (emptyState) emptyState.hidden = true;
    }
});
document.body.addEventListener('htmx:afterSettle', function() {
    var list = document.getElementById('next-actions-list');
    var emptyState = document.getElementById('next-actions-empty-state');
    if (list && list.children.length === 0 && emptyState) {
        list.hidden = true;
        emptyState.hidden = false;
    }
});
</script>
{% endblock %}

use sqlx::PgPool;

use crate::domain::{ContextId, NextAction, NextActionId, TodoTitle, TodoTitleError, UserId};
use crate::infrastructure::next_action_repository;

#[derive(Debug, thiserror::Error)]
pub enum AddNextActionError {
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "add_next_action",
    skip(pool, title),
    fields(user_id = %user_id.as_uuid(), context_id = %context_id.as_uuid())
)]
pub async fn add_next_action(
    pool: &PgPool,
    user_id: UserId,
    context_id: ContextId,
    title: String,
) -> Result<NextAction, AddNextActionError> {
    let title = TodoTitle::parse(title)?;
    let action = NextAction::new(user_id, context_id, title);

    next_action_repository::insert_next_action(pool, &action)
        .await
        .map_err(|e| {
            AddNextActionError::Unexpected(anyhow::anyhow!("Failed to insert next action: {e}"))
        })?;

    tracing::info!("Next action added");
    Ok(action)
}

#[tracing::instrument(
    name = "list_active_next_actions",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn list_active_next_actions(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<NextAction>, anyhow::Error> {
    let actions = next_action_repository::find_active_next_actions_by_user(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to fetch next actions: {e}"))?;

    Ok(actions)
}

#[tracing::instrument(
    name = "list_active_next_actions_by_context",
    skip(pool),
    fields(user_id = %user_id.as_uuid(), context_id = %context_id.as_uuid())
)]
pub async fn list_active_next_actions_by_context(
    pool: &PgPool,
    user_id: &UserId,
    context_id: &ContextId,
) -> Result<Vec<NextAction>, anyhow::Error> {
    let actions = next_action_repository::find_active_next_actions_by_user_and_context(
        pool, user_id, context_id,
    )
    .await
    .map_err(|e| anyhow::anyhow!("Failed to fetch next actions by context: {e}"))?;

    Ok(actions)
}

#[tracing::instrument(
    name = "count_active_next_actions",
    skip(pool),
    fields(user_id = %user_id.as_uuid())
)]
pub async fn count_active_next_actions(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<i64, anyhow::Error> {
    let count = next_action_repository::count_active_next_actions(pool, user_id)
        .await
        .map_err(|e| anyhow::anyhow!("Failed to count next actions: {e}"))?;

    Ok(count)
}

#[derive(Debug, thiserror::Error)]
pub enum CompleteNextActionError {
    #[error("Next action not found")]
    NotFound,
    #[error("Not authorized to complete this next action")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "complete_next_action",
    skip(pool),
    fields(action_id = %action_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn complete_next_action(
    pool: &PgPool,
    action_id: &NextActionId,
    user_id: &UserId,
) -> Result<(), CompleteNextActionError> {
    let action = next_action_repository::find_next_action_by_id(pool, action_id)
        .await
        .map_err(|e| CompleteNextActionError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(CompleteNextActionError::NotFound)?;

    if action.user_id() != user_id {
        return Err(CompleteNextActionError::Unauthorized);
    }

    let completed = action.complete();
    if let NextAction::Completed { completed_at, .. } = &completed {
        next_action_repository::complete_next_action(pool, action_id, completed_at)
            .await
            .map_err(|e| {
                CompleteNextActionError::Unexpected(anyhow::anyhow!(
                    "Failed to complete next action: {e}"
                ))
            })?;
    }

    tracing::info!("Next action completed");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum DeleteNextActionError {
    #[error("Next action not found")]
    NotFound,
    #[error("Not authorized to delete this next action")]
    Unauthorized,
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "delete_next_action",
    skip(pool),
    fields(action_id = %action_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn delete_next_action(
    pool: &PgPool,
    action_id: &NextActionId,
    user_id: &UserId,
) -> Result<(), DeleteNextActionError> {
    let action = next_action_repository::find_next_action_by_id(pool, action_id)
        .await
        .map_err(|e| DeleteNextActionError::Unexpected(anyhow::anyhow!("Database error: {e}")))?
        .ok_or(DeleteNextActionError::NotFound)?;

    if action.user_id() != user_id {
        return Err(DeleteNextActionError::Unauthorized);
    }

    next_action_repository::delete_next_action(pool, action_id)
        .await
        .map_err(|e| {
            DeleteNextActionError::Unexpected(anyhow::anyhow!("Failed to delete next action: {e}"))
        })?;

    tracing::info!("Next action deleted");
    Ok(())
}

#[derive(Debug, thiserror::Error)]
pub enum UpdateNextActionTitleError {
    #[error("Next action not found")]
    NotFound,
    #[error("Not authorized to edit this next action")]
    Unauthorized,
    #[error("Invalid title: {0}")]
    InvalidTitle(#[from] TodoTitleError),
    #[error(transparent)]
    Unexpected(#[from] anyhow::Error),
}

#[tracing::instrument(
    name = "update_next_action_title",
    skip(pool, new_title),
    fields(action_id = %action_id.as_uuid(), user_id = %user_id.as_uuid())
)]
pub async fn update_next_action_title(
    pool: &PgPool,
    action_id: &NextActionId,
    user_id: &UserId,
    new_title: String,
) -> Result<(), UpdateNextActionTitleError> {
    let action = next_action_repository::find_next_action_by_id(pool, action_id)
        .await
        .map_err(|e| {
            UpdateNextActionTitleError::Unexpected(anyhow::anyhow!("Database error: {e}"))
        })?
        .ok_or(UpdateNextActionTitleError::NotFound)?;

    if action.user_id() != user_id {
        return Err(UpdateNextActionTitleError::Unauthorized);
    }

    let title = TodoTitle::parse(new_title)?;

    next_action_repository::update_next_action_title(pool, action_id, &title)
        .await
        .map_err(|e| {
            UpdateNextActionTitleError::Unexpected(anyhow::anyhow!(
                "Failed to update next action title: {e}"
            ))
        })?;

    tracing::info!("Next action title updated");
    Ok(())
}

use chrono::{DateTime, Utc};
use sqlx::PgPool;
use uuid::Uuid;

use crate::domain::{ContextId, NextAction, NextActionId, TodoTitle, UserId};

struct NextActionRecord {
    id: Uuid,
    user_id: Uuid,
    context_id: Uuid,
    title: String,
    created_at: DateTime<Utc>,
    completed_at: Option<DateTime<Utc>>,
}

impl NextActionRecord {
    fn into_domain(self) -> NextAction {
        let id = NextActionId::from_uuid(self.id);
        let user_id = UserId::from_uuid(self.user_id);
        let context_id = ContextId::from_uuid(self.context_id);
        let title = TodoTitle::parse(self.title).expect("stored title should be valid");

        NextAction::from_parts(
            id,
            user_id,
            context_id,
            title,
            self.created_at,
            self.completed_at,
        )
    }
}

pub async fn insert_next_action(pool: &PgPool, action: &NextAction) -> Result<(), sqlx::Error> {
    let completed_at: Option<&DateTime<Utc>> = match action {
        NextAction::Completed { completed_at, .. } => Some(completed_at),
        NextAction::Active { .. } => None,
    };

    sqlx::query!(
        r#"INSERT INTO next_actions (id, user_id, context_id, title, created_at, completed_at)
           VALUES ($1, $2, $3, $4, $5 :: timestamptz, $6 :: timestamptz)"#,
        action.id().as_uuid(),
        action.user_id().as_uuid(),
        action.context_id().as_uuid(),
        action.title().as_str(),
        action.created_at() as &DateTime<Utc>,
        completed_at as Option<&DateTime<Utc>>,
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn find_active_next_actions_by_user(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<Vec<NextAction>, sqlx::Error> {
    let records = sqlx::query_as!(
        NextActionRecord,
        r#"SELECT id, user_id, context_id, title,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>"
           FROM next_actions
           WHERE user_id = $1 AND completed_at IS NULL
           ORDER BY created_at ASC"#,
        user_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records
        .into_iter()
        .map(|r: NextActionRecord| r.into_domain())
        .collect())
}

pub async fn find_active_next_actions_by_user_and_context(
    pool: &PgPool,
    user_id: &UserId,
    context_id: &ContextId,
) -> Result<Vec<NextAction>, sqlx::Error> {
    let records = sqlx::query_as!(
        NextActionRecord,
        r#"SELECT id, user_id, context_id, title,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>"
           FROM next_actions
           WHERE user_id = $1 AND context_id = $2 AND completed_at IS NULL
           ORDER BY created_at ASC"#,
        user_id.as_uuid(),
        context_id.as_uuid(),
    )
    .fetch_all(pool)
    .await?;

    Ok(records
        .into_iter()
        .map(|r: NextActionRecord| r.into_domain())
        .collect())
}

pub async fn find_next_action_by_id(
    pool: &PgPool,
    action_id: &NextActionId,
) -> Result<Option<NextAction>, sqlx::Error> {
    let record: Option<NextActionRecord> = sqlx::query_as!(
        NextActionRecord,
        r#"SELECT id, user_id, context_id, title,
           created_at as "created_at: DateTime<Utc>",
           completed_at as "completed_at: DateTime<Utc>"
           FROM next_actions WHERE id = $1"#,
        action_id.as_uuid(),
    )
    .fetch_optional(pool)
    .await?;

    Ok(record.map(|r: NextActionRecord| r.into_domain()))
}

pub async fn complete_next_action(
    pool: &PgPool,
    action_id: &NextActionId,
    completed_at: &DateTime<Utc>,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE next_actions SET completed_at = $1 :: timestamptz WHERE id = $2"#,
        completed_at as &DateTime<Utc>,
        action_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn delete_next_action(
    pool: &PgPool,
    action_id: &NextActionId,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"DELETE FROM next_actions WHERE id = $1"#,
        action_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn update_next_action_title(
    pool: &PgPool,
    action_id: &NextActionId,
    title: &TodoTitle,
) -> Result<(), sqlx::Error> {
    sqlx::query!(
        r#"UPDATE next_actions SET title = $1 WHERE id = $2"#,
        title.as_str(),
        action_id.as_uuid(),
    )
    .execute(pool)
    .await?;
    Ok(())
}

pub async fn count_active_next_actions(
    pool: &PgPool,
    user_id: &UserId,
) -> Result<i64, sqlx::Error> {
    let record = sqlx::query!(
        r#"SELECT COUNT(*) as "count!" FROM next_actions WHERE user_id = $1 AND completed_at IS NULL"#,
        user_id.as_uuid(),
    )
    .fetch_one(pool)
    .await?;

    Ok(record.count)
}

